     2→//! src/module_15.rs
     3→//!
     4→//! An event–driven badge–awarding micro-service for the
     5→//! “EduPulse Live – Event-Driven Social Learning Hub” platform.
     6→//!
     7→//! This module demonstrates how the core application publishes
     8→//! domain events while an out-of-process, autonomous component
     9→//! (here: `BadgeAwardService`) consumes them, performs business
    10→//! logic, persists the result and publishes its own follow-up
    11→//! events.  
    12→//!
    13→//! The service is completely self-contained: it hosts an in-memory
    14→//! dispatcher for local development, yet persists events and state
    15→//! in Postgres so it can be moved into a distributed setting
    16→//! later on (e.g. with NATS/Kafka‐backed `Dispatcher`).
    17→//!
    18→//! Architectural patterns shown here:
    19→//!   • Repository Pattern      – decoupling persistence
    20→//!   • Service Layer           – `BadgeAwardService`
    21→//!   • Event Sourcing          – immutable `EventStore`
    22→//!   • Async Rust w/ Tokio     – non-blocking I/O
    23→//!   • Error Handling w/ thiserror + anyhow
    24→//!
    25→//! NOTE: In a real-world project this module would be split
    26→//! into several files/crates.  Everything is co-located here only
    27→//! to satisfy the single-file constraint of the exercise.
    28→
    29→use std::{
    30→    collections::HashSet,
    31→    sync::Arc,
    32→    time::Duration,
    33→};
    34→
    35→use async_trait::async_trait;
    36→use chrono::{DateTime, Utc};
    37→use serde::{Deserialize, Serialize};
    38→use sqlx::{postgres::PgPoolOptions, PgPool};
    39→use thiserror::Error;
    40→use tokio::{
    41→    select,
    42→    sync::{broadcast, mpsc, RwLock},
    43→    task::JoinHandle,
    44→};
    45→use uuid::Uuid;
    46→
    47→/// Domain events which can be emitted by EduPulse services.
    48→///
    49→/// IMPORTANT: New variants **must** implement `Serialize`/`Deserialize`
    50→/// so they can be persisted in the event store.
    51→#[derive(Debug, Clone, Serialize, Deserialize)]
    52→#[serde(tag = "type", content = "payload")]
    53→pub enum DomainEvent {
    54→    QuizSubmitted(QuizSubmitted),
    55→    BadgeAwarded(BadgeAwarded),
    56→    // … more variants omitted for brevity
    57→}
    58→
    59→impl DomainEvent {
    60→    /// Helper returning event name for logging / metrics.
    61→    pub fn name(&self) -> &'static str {
    62→        match self {
    63→            DomainEvent::QuizSubmitted(_) => "QuizSubmitted",
    64→            DomainEvent::BadgeAwarded(_) => "BadgeAwarded",
    65→        }
    66→    }
    67→}
    68→
    69→/// Metadata common to all envelopes—separates immutable event data
    70→/// from peripheral transport concerns such as IDs and timestamps.
    71→#[derive(Debug, Clone, Serialize, Deserialize)]
    72→pub struct EventEnvelope {
    73→    pub id: Uuid,
    74→    pub occurred_at: DateTime<Utc>,
    75→    pub event: DomainEvent,
    76→}
    77→
    78→impl EventEnvelope {
    79→    pub fn new(event: DomainEvent) -> Self {
    80→        Self {
    81→            id: Uuid::new_v4(),
    82→            occurred_at: Utc::now(),
    83→            event,
    84→        }
    85→    }
    86→}
    87→
    88→/// Event data triggered when a learner submits a quiz.
    89→#[derive(Debug, Clone, Serialize, Deserialize)]
    90→pub struct QuizSubmitted {
    91→    pub quiz_id: Uuid,
    92→    pub learner_id: Uuid,
    93→    pub score: f32,
    94→}
    95→
    96→/// Event data emitted once the learner qualifies for a badge.
    97→#[derive(Debug, Clone, Serialize, Deserialize)]
    98→pub struct BadgeAwarded {
    99→    pub badge_id: Uuid,
   100→    pub learner_id: Uuid,
   101→    pub awarded_at: DateTime<Utc>,
   102→    pub reason: String,
   103→}
   104→
   105→/// Central event dispatcher.  
   106→/// Internally uses a Tokio broadcast channel so any number of
   107→/// in-process consumers can receive events concurrently.
   108→///
   109→/// In production you might replace the implementation with NATS,
   110→/// Kafka, RabbitMQ… etc., leaving the public API intact.
   111→#[derive(Clone)]
   112→pub struct Dispatcher {
   113→    sender: broadcast::Sender<EventEnvelope>,
   114→}
   115→
   116→impl Dispatcher {
   117→    /// Create a new dispatcher with a configurable ring buffer size.
   118→    pub fn new(channel_size: usize) -> Self {
   119→        let (sender, _rx) = broadcast::channel(channel_size);
   120→        Self { sender }
   121→    }
   122→
   123→    /// Publish an envelope to all subscribers.
   124→    pub async fn publish(&self, envelope: EventEnvelope) {
   125→        // broadcast::Sender::send is synchronous but inexpensive.
   126→        // Failure only occurs when there are no active receivers;
   127→        // still, we ignore that because the event is persisted in
   128→        // the store before reaching this point.
   129→        let _ = self.sender.send(envelope);
   130→    }
   131→
   132→    /// Subscribe to a continuous stream of events.
   133→    pub fn subscribe(&self) -> broadcast::Receiver<EventEnvelope> {
   134→        self.sender.subscribe()
   135→    }
   136→}
   137→
   138→/// Persisted event stream; provides idempotent append + read access.
   139→/// Uses Postgres JSONB for flexible schema evolution.
   140→///
   141→/// Table DDL (run via migrations):
   142→/// ```sql
   143→/// CREATE TABLE IF NOT EXISTS event_store (
   144→///     id           UUID PRIMARY KEY,
   145→///     occurred_at  TIMESTAMP WITH TIME ZONE NOT NULL,
   146→///     event_name   TEXT NOT NULL,
   147→///     payload      JSONB NOT NULL
   148→/// );
   149→/// ```
   150→pub struct EventStore {
   151→    pool: PgPool,
   152→}
   153→
   154→impl EventStore {
   155→    pub async fn new(db_url: &str, max_connections: u32) -> Result<Self, sqlx::Error> {
   156→        let pool = PgPoolOptions::new()
   157→            .max_connections(max_connections)
   158→            .connect(db_url)
   159→            .await?;
   160→        Ok(Self { pool })
   161→    }
   162→
   163→    /// Append envelope to store.
   164→    pub async fn append(&self, env: &EventEnvelope) -> Result<(), sqlx::Error> {
   165→        sqlx::query!(
   166→            r#"
   167→            INSERT INTO event_store (id, occurred_at, event_name, payload)
   168→            VALUES ($1, $2, $3, $4)
   169→            "#,
   170→            env.id,
   171→            env.occurred_at,
   172→            env.event.name(),
   173→            serde_json::to_value(&env.event)?
   174→        )
   175→        .execute(&self.pool)
   176→        .await?;
   177→        Ok(())
   178→    }
   179→
   180→    /// Read events by name—useful for rebuilding read models.
   181→    pub async fn load_by_event(
   182→        &self,
   183→        event_name: &str,
   184→    ) -> Result<Vec<EventEnvelope>, sqlx::Error> {
   185→        let recs = sqlx::query!(
   186→            r#"
   187→            SELECT id, occurred_at, payload
   188→            FROM event_store
   189→            WHERE event_name = $1
   190→            ORDER BY occurred_at ASC
   191→            "#,
   192→            event_name
   193→        )
   194→        .fetch_all(&self.pool)
   195→        .await?;
   196→
   197→        recs.into_iter()
   198→            .map(|r| {
   199→                let event = match event_name {
   200→                    "QuizSubmitted" => DomainEvent::QuizSubmitted(
   201→                        serde_json::from_value(r.payload)?,
   202→                    ),
   203→                    "BadgeAwarded" => DomainEvent::BadgeAwarded(
   204→                        serde_json::from_value(r.payload)?,
   205→                    ),
   206→                    _ => unreachable!("Unknown event stored in DB"),
   207→                };
   208→                Ok(EventEnvelope {
   209→                    id: r.id,
   210→                    occurred_at: r.occurred_at,
   211→                    event,
   212→                })
   213→            })
   214→            .collect()
   215→    }
   216→}
