   218→/// Error type covering all repository/service error cases.
   219→#[derive(Error, Debug)]
   220→pub enum ServiceError {
   221→    #[error("Database error: {0}")]
   222→    Database(#[from] sqlx::Error),
   223→
   224→    #[error("Event serialisation error: {0}")]
   225→    Serde(#[from] serde_json::Error),
   226→
   227→    #[error("Internal channel closed")]
   228→    ChannelClosed,
   229→}
