   231→/// Repository abstraction for badge persistence.
   232→#[async_trait]
   233→pub trait BadgeRepository: Send + Sync {
   234→    async fn learner_already_has_badge(
   235→        &self,
   236→        learner_id: Uuid,
   237→        badge_id: Uuid,
   238→    ) -> Result<bool, ServiceError>;
   239→
   240→    async fn assign_badge(
