    45→/// A marker trait implemented by *every* domain event.
    46→///
    47→/// The obvious choice would be enum-dispatch, however a trait object allows new
    48→/// events to be added without modifying a central enum – a desirable property
    49→/// in a highly modular micro-service code-base.
    50→#[async_trait]
    51→pub trait DomainEvent: Send + Sync {
    52→    /// Type discriminator (`"submission.created"`, `"plagiarism.checked"`, …).
    53→    fn event_type(&self) -> &'static str;
    54→
    55→    /// Monotonic temporal marker.
    56→    fn occurred_at(&self) -> DateTime<Utc>;
    57→
    58→    /// Correlation id used for distributed tracing.
    59→    fn correlation_id(&self) -> &CorrelationId;
    60→
    61→    /// Serialize event instance to JSON for transport on the wire.
    62→    fn to_json(&self) -> Result<Vec<u8>, EventError> {
    63→        serde_json::to_vec(self).map_err(EventError::serialization)
    64→    }
    65→}
