    71→    Serialization(#[from] serde_json::Error),
    72→
    73→    #[error("http error: {0}")]
    74→    Http(#[from] reqwest::Error),
    75→
    76→    #[error("event bus error: {0}")]
    77→    EventBus(String),
    78→
    79→    #[error("timeout waiting for plagiarism service")]
    80→    TimeOut,
    81→
    82→    #[error("unexpected response from plagiarism service: {0}")]
    83→    InvalidPlagiarismResponse(String),
