   168→/// Event bus abstraction.
   169→#[async_trait]
   170→pub trait EventBus {
   171→    async fn publish(&self, event: &(dyn DomainEvent + 'static)) -> Result<(), EventError>;
   172→
   173→    /// Subscribe with a channel of boxed events.   
   174→    ///
   175→    /// In real life we would use strongly typed channels; for brevity we
   176→    /// down-cast at the consuming site.
   177→    async fn subscribe(&self) -> mpsc::Receiver<Box<dyn DomainEvent>>;
   178→}
   179→
   180→/// In-memory implementation (dev / tests).
   181→pub struct InMemoryEventBus {
   182→    tx: mpsc::Sender<Box<dyn DomainEvent>>,
   183→    rx: RwLock<mpsc::Receiver<Box<dyn DomainEvent>>>,
   184→}
   185→
   186→impl InMemoryEventBus {
   187→    pub fn new(buffer: usize) -> Self {
   188→        let (tx, rx) = mpsc::channel(buffer);
   189→        Self {
   190→            tx,
   191→            rx: RwLock::new(rx),
   192→        }
   193→    }
   194→}
   195→
   196→#[async_trait]
   197→impl EventBus for InMemoryEventBus {
   198→    async fn publish(&self, event: &(dyn DomainEvent + 'static)) -> Result<(), EventError> {
   199→        let mut cloned = Vec::new();
   200→        // Re-serialize to guarantee we send a **copy** (preventing accidental
   201→        // mutation from other tasks).
   202→        let bytes = event.to_json()?;
   203→        let evt_type = event.event_type();
   204→        cloned.extend_from_slice(&bytes);
   205→
   206→        let deserialized: Box<dyn DomainEvent> = match evt_type {
   207→            "submission.created" => {
   208→                let ev: SubmissionCreated = serde_json::from_slice(&cloned)?;
   209→                Box::new(ev)
   210→            }
   211→            "plagiarism.checked" => {
   212→                let ev: PlagiarismChecked = serde_json::from_slice(&cloned)?;
   213→                Box::new(ev)
   214→            }
   215→            "autoscore.completed" => {
   216→                let ev: AutoScoreCompleted = serde_json::from_slice(&cloned)?;
   217→                Box::new(ev)
   218→            }
   219→            _ => {
   220→                warn!("unrecognized event type on in-memory bus: {evt_type}");
   221→                return Ok(());
   222→            }
   223→        };
   224→        self.tx
   225→            .send(deserialized)
   226→            .await
   227→            .map_err(|e| EventError::EventBus(e.to_string()))
   228→    }
   229→
   230→    async fn subscribe(&self) -> mpsc::Receiver<Box<dyn DomainEvent>> {
   231→        self.rx.write().await.recv().await;
   232→        // clone underlying channel
   233→        let mut rx = self.rx.write().await;
   234→        rx.clone()
   235→    }
   236→}
