   238→/// Application service orchestrating plagiarism & auto-scoring.
   239→pub struct LearningPulseService {
   240→    event_bus: Arc<dyn EventBus + Send + Sync>,
   241→    http: reqwest::Client,
   242→    plagiarism_endpoint: String,
   243→    rubric_store: Arc<RubricRepository>,
