   245→
   246→impl LearningPulseService {
   247→    pub fn new(
   248→        event_bus: Arc<dyn EventBus + Send + Sync>,
   249→        plagiarism_endpoint: impl Into<String>,
   250→        rubric_store: Arc<RubricRepository>,
   251→    ) -> Self {
