   259→
   260→    /// Run the long-running background task.
   261→    pub fn spawn(self: Arc<Self>) -> JoinHandle<()> {
   262→        tokio::spawn(async move {
   263→            let mut rx = self.event_bus.subscribe().await;
   264→            info!("learning-pulse service ready to process events");
   265→            while let Some(evt) = rx.recv().await {
   266→                if let Some(submission_evt) = evt.downcast_ref::<SubmissionCreated>() {
   267→                    let svc = self.clone();
   268→                    tokio::spawn(async move {
   269→                        if let Err(err) = svc.process_submission(submission_evt.clone()).await {
   270→                            error!(?err, "failed to process submission");
   271→                        }
   272→                    });
   273→                }
   274→            }
   275→        })
   276→    }
