   278→    #[instrument(skip_all, fields(submission_id = %submission.submission_id))]
   279→    async fn process_submission(&self, submission: SubmissionCreated) -> Result<(), EventError> {
   280→        let correlation_id = submission.correlation_id.clone();
   281→
   282→        // 1) Spawn plagiarism request
   283→        let plagiarism_future = self
   284→            .request_plagiarism_check(&submission)
   285→            .await
   286→            .map(|res| PlagiarismChecked {
   287→                submission_id: submission.submission_id.clone(),
   288→                similarity_score: res.score,
   289→                is_suspect: res.is_suspect,
   290→                occurred_at: Utc::now(),
   291→                correlation_id: correlation_id.clone(),
   292→            });
   293→
   294→        match plagiarism_future {
   295→            Ok(evt) => {
   296→                self.event_bus.publish(&evt).await?;
   297→            }
   298→            Err(e) => error!(?e, "plagiarism check failed"),
   299→        }
   300→
   301→        // 2) Spawn scoring
   302→        let score_evt = self
   303→            .auto_score(&submission)
   304→            .await
   305→            .map(|score| AutoScoreCompleted {
   306→                submission_id: submission.submission_id.clone(),
   307→                score,
   308→                rubric_version: self.rubric_store.latest_version(),
   309→                occurred_at: Utc::now(),
   310→                correlation_id,
   311→            })?;
   312→
   313→        self.event_bus.publish(&score_evt).await?;
   314→        Ok(())
   315→    }
