   317→    /// Calls the external plagiarism API (with timeout protection).
   318→    async fn request_plagiarism_check(
   319→        &self,
   320→        submission: &SubmissionCreated,
   321→    ) -> Result<PlagiarismResponse, EventError> {
   322→        #[derive(Serialize)]
   323→        struct Payload<'a> {
   324→            submission_id: &'a str,
   325→            content: &'a str,
   326→            student_id: &'a str,
   327→        }
   328→
   329→        let body = Payload {
   330→            submission_id: &submission.submission_id,
   331→            content: &submission.content,
   332→            student_id: &submission.author_id,
   333→        };
   334→
   335→        let request = self
   336→            .http
   337→            .post(&self.plagiarism_endpoint)
   338→            .json(&body)
   339→            .build()?;
   340→
   341→        let response = timeout(Duration::from_secs(8), self.http.execute(request)).await;
   342→
   343→        let response = match response {
   344→            Ok(res) => res?,
   345→            Err(_) => return Err(EventError::TimeOut),
   346→        };
   347→
   348→        if response.status() != StatusCode::OK {
   349→            return Err(EventError::InvalidPlagiarismResponse(format!(
   350→                "status {}",
   351→                response.status()
   352→            )));
   353→        }
   354→
   355→        let result: PlagiarismApiPayload = response.json().await?;
   356→        Ok(result.into())
   357→    }
