   359→    /// Very naive auto-scoring based on a rubric repository.
   360→    async fn auto_score(&self, submission: &SubmissionCreated) -> Result<u8, EventError> {
   361→        let rubric = self.rubric_store.fetch_current().await;
   362→        let words = submission.content.split_whitespace().count() as u32;
   363→        let mut score = 0;
   364→
   365→        if words >= rubric.min_word_count {
   366→            score += 60;
   367→        }
   368→        if submission.content.contains("because") {
   369→            score += 15;
   370→        }
   371→        if submission.content.contains("therefore") {
   372→            score += 15;
   373→        }
   374→        if submission.content.ends_with('.') {
   375→            score += 10;
   376→        }
   377→        Ok(score.min(100) as u8)
   378→    }
   379→}
