   228→/// Outbox service coordinates persistence and dispatching.
   229→pub struct OutboxService<R: OutboxRepository + Send + Sync> {
   230→    repo:        Arc<R>,
   231→    nats_url:    String,
   232→    key_pair:    Arc<Ed25519KeyPair>,
   233→    // Retry/backoff configuration.
   234→    max_batch:   i64,
   235→    poll_every:  Duration,
