   237→
   238→impl<R: OutboxRepository + Send + Sync> OutboxService<R> {
   239→    pub fn new(
   240→        repo: Arc<R>,
   241→        nats_url: impl Into<String>,
   242→        key_pair: Ed25519KeyPair,
   243→    ) -> Self {
   244→        Self {
   245→            repo,
   246→            nats_url: nats_url.into(),
   247→            key_pair: Arc::new(key_pair),
   248→            max_batch: 256,
   249→            poll_every: Duration::from_secs(2),
