   252→
   253→    /// Persists a domain event within an existing transaction.
   254→    ///
   255→    /// This method is *synchronous* with respect to the caller’s DB
   256→    /// transaction; the actual dispatch happens in the background
   257→    /// daemon spawned by `run_dispatch_loop`.
   258→    pub async fn stage_event<E: DomainEvent>(
   259→        &self,
   260→        tx: &mut Transaction<'_, Postgres>,
   261→        aggregate_id: Uuid,
   262→        event: &E,
   263→    ) -> Result<(), OutboxError> {
   264→        let payload = serde_json::to_value(event)
   265→            .map_err(|e| OutboxError::Other(format!("serde: {e}")))?;
   266→
   267→        let mut unsigned = EventEnvelope {
   268→            id:           Uuid::new_v4(),
   269→            aggregate_id,
   270→            event_type:   event.event_type().to_owned(),
   271→            payload,
   272→            occurred_at:  Utc::now(),
   273→            signature:    String::new(), // placeholder
   274→        };
   275→
   276→        unsigned.signature = self.sign_payload(&unsigned)?;
   277→
   278→        self.repo.insert(tx, &unsigned).await
   279→    }
   280→
   281→    /// Infinite loop: regularly pulls unsent events and publishes them.
   282→    ///
   283→    /// Should be run in its own Tokio task; gracefully stops when the
   284→    /// task is cancelled.
   285→    pub async fn run_dispatch_loop(self: Arc<Self>) -> Result<(), OutboxError> {
   286→        let nats_conn = async_nats::connect(self.nats_url.clone()).await?;
   287→
   288→        loop {
   289→            // Fetch up to `max_batch` events that still need sending.
   290→            let events = self.repo.fetch_unsent(self.max_batch).await?;
   291→
   292→            if events.is_empty() {
   293→                sleep(self.poll_every).await;
   294→                continue;
   295→            }
   296→
   297→            // We use a `FuturesUnordered` stream to publish in parallel
   298→            // while still limiting overall memory / network utilisation.
   299→            let publish_fut = stream::iter(events.clone())
   300→                .map(|evt| {
   301→                    let conn = &nats_conn;
   302→                    async move {
   303→                        conn.publish(evt.subject(), serde_json::to_vec(&evt)?)
   304→                            .await
   305→                            .map_err(OutboxError::from)
   306→                    }
   307→                })
   308→                .buffer_unordered(16)
   309→                .collect::<Vec<_>>();
   310→
   311→            let results = publish_fut.await;
   312→
   313→            // Separate errors from successes for partial retries.
   314→            let (oks, errs): (Vec<_>, Vec<_>) =
   315→                results.into_iter().partition(Result::is_ok);
   316→
   317→            if !oks.is_empty() {
   318→                // Only mark events sent when the publish actually succeeded.
   319→                let sent_events: Vec<_> = events
   320→                    .iter()
   321→                    .zip(oks)
   322→                    .filter_map(|(evt, res)| res.ok().map(|_| evt.clone()))
   323→                    .collect();
   324→
   325→                self.repo.mark_sent(&sent_events).await?;
   326→            }
   327→
   328→            if !errs.is_empty() {
   329→                // Log and backoff; caller decides global error handling.
   330→                tracing::warn!(
   331→                    failed = errs.len(),
   332→                    "Some messages failed to publish; will retry"
   333→                );
