   335→                sleep(self.poll_every * 2).await;
   336→            }
   337→        }
   338→    }
   339→
   340→    fn sign_payload(&self, envelope: &EventEnvelope) -> Result<String, OutboxError> {
   341→        let mut bytes = serde_json::to_vec(envelope)
   342→            .map_err(|e| OutboxError::Other(format!("serde: {e}")))?;
   343→
   344→        // Sign the raw bytes (comment this if you prefer canonical JSON).
   345→        let sig = self.key_pair.sign(&mut bytes);
   346→        Ok(base64::encode(sig.as_ref()))
   347→    }
   348→}
