   370→/// or a TPM; this simplistic helper is for local development only.
   371→pub fn load_signing_key() -> Result<Ed25519KeyPair, OutboxError> {
   372→    use ring::rand::SystemRandom;
   373→    use ring::signature::Ed25519KeyPair as Key;
   374→
   375→    if let Ok(pkcs8_b64) = std::env::var("EDUPULSE_SIGNING_KEY_B64") {
