   382→        let pkcs8 = Key::generate_pkcs8(&rng).map_err(|_| OutboxError::Crypto)?;
   383→        Ok(Key::from_pkcs8(pkcs8.as_ref()).map_err(|_| OutboxError::Crypto)?)
   384→    }
   385→}
