    71→/// A single row inside the `outbox_events` table.
    72→///
    73→/// NOTE: `payload` is stored as **raw JSON** to keep the table generic and
    74→/// future-proof.  Consumers can decode it based on the `event_type`.
    75→#[derive(Debug, Serialize, Deserialize, Clone)]
    76→pub struct OutboxEvent {
    77→    pub id: Uuid,
    78→    pub aggregate_type: String,
    79→    pub aggregate_id: Uuid,
    80→    pub event_type: String,
