    89→
    90→#[derive(Error, Debug)]
    91→pub enum OutboxError {
    92→    #[error("database error: {0}")]
    93→    Database(#[from] sqlx::Error),
    94→
    95→    #[error("AMQP error: {0}")]
    96→    Amqp(#[from] lapin::Error),
