   103→/*                           Outbox Repository (DAO)                          */
   104→/* -------------------------------------------------------------------------- */
   105→
   106→/// Repository responsible for accessing the `outbox_events` table.
   107→#[derive(Clone)]
   108→pub struct OutboxRepository {
   109→    pool: PgPool,
   110→}
   111→
   112→impl OutboxRepository {
   113→    pub fn new(pool: PgPool) -> Self {
   114→        Self { pool }
   115→    }
   116→
   117→    /// Inserts a new [`OutboxEvent`] within an existing transaction or
   118→    /// standalone if `tx` is `None`.
   119→    pub async fn insert(
   120→        &self,
   121→        mut event: OutboxEvent,
   122→        tx: Option<&mut sqlx::Transaction<'_, sqlx::Postgres>>,
   123→    ) -> Result<OutboxEvent, OutboxError> {
   124→        event.id = event.id; // ensure id exists
   125→        let query = sqlx::query!(
   126→            r#"
   127→            INSERT INTO outbox_events (
   128→                id,
   129→                aggregate_type,
   130→                aggregate_id,
   131→                event_type,
   132→                payload,
   133→                occurred_at,
   134→                published_at
   135→            ) VALUES ($1,$2,$3,$4,$5,$6,$7)
   136→            "#,
   137→            event.id,
   138→            event.aggregate_type,
   139→            event.aggregate_id,
   140→            event.event_type,
   141→            event.payload,
   142→            event.occurred_at,
   143→            event.published_at
   144→        );
   145→
   146→        match tx {
   147→            Some(tx_ref) => {
   148→                query.execute(&mut *tx_ref).await?;
   149→            }
   150→            None => {
   151→                query.execute(&self.pool).await?;
   152→            }
   153→        }
   154→
   155→        Ok(event)
   156→    }
   157→
   158→    /// Fetches a batch of unpublished events, ordered by `occurred_at`.
   159→    pub async fn fetch_unpublished(
   160→        &self,
   161→        limit: i64,
   162→    ) -> Result<Vec<OutboxEvent>, OutboxError> {
   163→        let rows = sqlx::query(
   164→            r#"
   165→            SELECT
   166→                id,
   167→                aggregate_type,
   168→                aggregate_id,
   169→                event_type,
   170→                payload,
   171→                occurred_at,
   172→                published_at
   173→            FROM outbox_events
   174→            WHERE published_at IS NULL
   175→            ORDER BY occurred_at
   176→            LIMIT $1
   177→            "#,
   178→        )
   179→        .bind(limit)
   180→        .map(|row: PgRow| OutboxEvent {
   181→            id: row.get("id"),
   182→            aggregate_type: row.get("aggregate_type"),
   183→            aggregate_id: row.get("aggregate_id"),
   184→            event_type: row.get("event_type"),
   185→            payload: row.get::<serde_json::Value, _>("payload"),
   186→            occurred_at: row.get("occurred_at"),
   187→            published_at: row.get("published_at"),
   188→        })
   189→        .fetch_all(&self.pool)
   190→        .await?;
   191→
   192→        Ok(rows)
   193→    }
   194→
   195→    /// Marks the event as published.
   196→    pub async fn mark_as_published(&self, id: Uuid) -> Result<(), OutboxError> {
   197→        sqlx::query!(
   198→            r#"
   199→            UPDATE outbox_events
   200→            SET published_at = NOW()
   201→            WHERE id = $1
   202→            "#,
   203→            id
   204→        )
   205→        .execute(&self.pool)
   206→        .await?;
   207→
   208→        Ok(())
   209→    }
   210→}
