   215→
   216→/// Trait that abstracts away the underlying message broker implementation.
   217→/// This allows swapping RabbitMQ for NATS, Kafka, etc. without touching the
   218→/// domain/application layer.
   219→#[async_trait]
   220→pub trait EventPublisher: Send + Sync + 'static {
