   232→    exchange: String,
   233→}
   234→
   235→impl RabbitMqPublisher {
   236→    /// Establishes a connection and ensures that the declared exchange exists.
   237→    pub async fn connect(
   238→        amqp_addr: &str,
   239→        exchange: &str,
   240→    ) -> Result<Self, OutboxError> {
   241→        let conn = Connection::connect(amqp_addr, ConnectionProperties::default()).await?;
   242→        let channel = conn.create_channel().await?;
   243→
   244→        channel
   245→            .queue_declare(
   246→                exchange,
   247→                QueueDeclareOptions::default(),
   248→                FieldTable::default(),
   249→            )
   250→            .await?;
   251→
   252→        Ok(Self {
   253→            channel: Arc::new(channel),
   254→            exchange: exchange.to_string(),
   255→        })
   256→    }
   257→}
