   259→#[async_trait]
   260→impl EventPublisher for RabbitMqPublisher {
   261→    async fn publish(&self, event: &OutboxEvent) -> Result<(), OutboxError> {
   262→        let payload = serde_json::to_vec(event)?;
   263→        self.channel
   264→            .basic_publish(
   265→                "",
   266→                &self.exchange,
   267→                BasicPublishOptions::default(),
