   281→/* -------------------------------------------------------------------------- */
   282→/*                            Outbox Processor                                */
   283→/* -------------------------------------------------------------------------- */
   284→
   285→/// Responsible for periodically polling the DB, publishing events and
   286→/// updating their status. It runs indefinitely in a tokio task.
   287→pub struct OutboxProcessor {
   288→    handle: JoinHandle<()>,
   289→}
   290→
   291→impl OutboxProcessor {
   292→    /// Spawns the background `OutboxProcessor` task with sensible defaults.
   293→    ///
   294→    /// `poll_interval` defaults to 500 ms and `batch_size` to 100.
   295→    pub fn spawn<P>(pool: PgPool, publisher: P) -> Self
   296→    where
   297→        P: EventPublisher,
   298→    {
   299→        let poll_interval = Duration::from_millis(500);
   300→        let batch_size = 100;
   301→
   302→        let repo = OutboxRepository::new(pool);
   303→        let publisher = Arc::new(publisher);
   304→
   305→        let handle = task::spawn(async move {
   306→            let mut interval = time::interval(poll_interval);
   307→            loop {
   308→                interval.tick().await;
   309→                if let Err(err) =
   310→                    Self::drain_batch(&repo, Arc::clone(&publisher), batch_size).await
   311→                {
   312→                    error!("Error draining outbox: {:?}", err);
   313→                }
   314→            }
   315→        });
   316→
   317→        Self { handle }
   318→    }
   319→
   320→    async fn drain_batch<P>(
   321→        repo: &OutboxRepository,
   322→        publisher: Arc<P>,
   323→        batch_size: i64,
   324→    ) -> Result<(), OutboxError>
   325→    where
   326→        P: EventPublisher,
   327→    {
   328→        // Fetch a batch; early return if empty
   329→        let events = repo.fetch_unpublished(batch_size).await?;
   330→        if events.is_empty() {
   331→            return Ok(());
   332→        }
   333→
   334→        // Publish events sequentially (could be parallel with `join_all` if
   335→        // ordering isn't important)
   336→        for event in events {
   337→            let op = || async {
   338→                publisher.publish(&event).await?;
   339→                repo.mark_as_published(event.id).await?;
   340→                Ok::<(), OutboxError>(())
   341→            };
   342→
   343→            // Retry with exponential back-off (max ~10 min)
   344→            let mut backoff = ExponentialBackoff {
   345→                initial_interval: Duration::from_millis(250),
   346→                multiplier: 2.0,
   347→                max_interval: Duration::from_secs(30),
   348→                max_elapsed_time: Some(Duration::from_secs(600)),
   349→                ..Default::default()
   350→            };
   351→
   352→            if let Err(err) = retry(backoff, op).await {
   353→                // This should rarely happen; send to Sentry, Dead-letter, etc.
   354→                warn!("Failed to publish event {}: {:?}", event.id, err);
   355→            }
   356→        }
   357→
   358→        Ok(())
   359→    }
   360→
   361→    /// Waits for the background task to finish (e.g. on graceful shutdown).
   362→    pub async fn join(self) -> Result<(), task::JoinError> {
   363→        self.handle.await
   364→    }
   365→}
