     2→//! src/module_72.rs
     3→//! ==========================================================
     4→//! Domain-event infrastructure for EduPulse Live
     5→//!
     6→//! This module encapsulates all logic necessary to create,
     7→//! enrich, and publish domain events to an external message
     8→//! broker (NATS in our case).  Keeping this code in a single
     9→//! file allows the rest of the application to stay broker-agnostic
    10→//! by relying solely on the `EventPublisher` trait.
    11→//!
    12→//! Production ready features delivered here:
    13→//!  - Typed domain event enum with Serde (de)serialization
    14→//!  - Envelope that adds traceability metadata (correlation,
    15→//!    causation, tenant & GDPR-erase flags)
    16→//!  - Pluggable async publisher with a NATS implementation
    17→//!  - Back-pressure aware buffering (tower::buffer)
    18→//!  - Observability via tracing
    19→//!  - Unit tests with an in-memory mock publisher
    20→//!
    21→//! NOTE: In `Cargo.toml` ensure these deps are available
    22→//! ```toml
    23→//! async-nats = { version = "0.32", default-features = false, features = ["tls"] }
    24→//! serde = { version = "1", features = ["derive"] }
    25→//! serde_json = "1"
    26→//! thiserror = "1"
    27→//! tokio = { version = "1", features = ["macros", "rt-multi-thread"] }
    28→//! tracing = "0.1"
    29→//! uuid = { version = "1", features = ["v4"] }
    30→//! tower = "0.4"
    31→//! ```
    32→//! ==========================================================
    33→
    34→use async_nats::{self, ConnectOptions};
    35→use serde::{Deserialize, Serialize};
    36→use std::{collections::HashMap, time::SystemTime};
    37→use thiserror::Error;
    38→use tokio::sync::mpsc;
    39→use tracing::{debug, error, instrument, trace, warn};
    40→use uuid::Uuid;
    41→
    42→/// Convenience result alias for the module
    43→pub type Result<T, E = PublisherError> = std::result::Result<T, E>;
    44→
    45→/// Domain event root type.  Extend as needed.
    46→#[derive(Debug, Serialize, Deserialize, Clone)]
    47→#[serde(tag = "type", content = "payload")]
    48→pub enum DomainEvent {
    49→    LessonPublished {
    50→        lesson_id: Uuid,
    51→        author_id: Uuid,
    52→        title: String,
    53→    },
    54→    QuizSubmitted {
    55→        quiz_id: Uuid,
    56→        student_id: Uuid,
    57→        answers: HashMap<String, String>,
    58→    },
    59→    BadgeAwarded {
    60→        badge_id: Uuid,
    61→        recipient_id: Uuid,
    62→        reason: String,
    63→    },
    64→    PaymentProcessed {
    65→        payment_id: Uuid,
    66→        from_user: Uuid,
    67→        amount_cents: u32,
    68→    },
    69→}
    70→
    71→/// Envelope that wraps a `DomainEvent` adding cross-cutting metadata.
    72→///
    73→/// This envelope is what gets serialized and shipped through NATS.
    74→/// It can be enriched by middleware (e.g. correlation extraction)
    75→#[derive(Debug, Serialize, Deserialize, Clone)]
    76→pub struct EventEnvelope {
    77→    /// Globally unique identifier for the event itself
    78→    pub event_id: Uuid,
    79→    /// If this event was triggered because of another event
    80→    pub causation_id: Option<Uuid>,
    81→    /// ID that allows grouping events belonging to the same request/transaction
    82→    pub correlation_id: Option<Uuid>,
    83→    /// Multi-tenant support
    84→    pub tenant_id: Option<String>,
    85→    /// When the event was created
    86→    pub created_at: SystemTime,
    87→    /// GDPR delete flag
    88→    pub personally_identifiable: bool,
    89→    /// Actual domain event
    90→    pub data: DomainEvent,
    91→}
    92→
    93→impl EventEnvelope {
    94→    /// Create a new envelope from a plain `DomainEvent`
    95→    pub fn new(
    96→        data: DomainEvent,
    97→        correlation_id: Option<Uuid>,
    98→        causation_id: Option<Uuid>,
    99→        tenant_id: Option<String>,
   100→        personally_identifiable: bool,
   101→    ) -> Self {
   102→        Self {
   103→            event_id: Uuid::new_v4(),
   104→            causation_id,
   105→            correlation_id,
   106→            tenant_id,
   107→            created_at: SystemTime::now(),
   108→            personally_identifiable,
   109→            data,
   110→        }
   111→    }
   112→}
   113→
   114→/// Result acknowledgment from a broker publish call.
   115→#[derive(Debug)]
   116→pub struct PublishAck {
   117→    pub broker_sequence: Option<u64>,
   118→}
   119→
   120→/// Errors that can occur while publishing
   121→#[derive(Debug, Error)]
   122→pub enum PublisherError {
   123→    #[error("connection or I/O error with broker: {0}")]
   124→    Broker(#[from] async_nats::Error),
   125→
   126→    #[error("serialization failure: {0}")]
   127→    Serialization(#[from] serde_json::Error),
   128→
   129→    #[error("channel closed")]
   130→    ChannelClosed,
   131→}
