   133→/// Contract for async event publishers.
   134→#[async_trait::async_trait]
   135→pub trait EventPublisher: Send + Sync {
   136→    /// Publishes an already-enveloped event.
   137→    async fn publish(&self, envelope: EventEnvelope) -> Result<PublishAck>;
   138→}
   139→
   140→/// No-op publisher useful for tests.
   141→pub struct InMemoryPublisher {
   142→    sender: mpsc::Sender<EventEnvelope>,
   143→}
   144→
   145→impl InMemoryPublisher {
   146→    pub fn new(buffer: usize) -> (Self, mpsc::Receiver<EventEnvelope>) {
   147→        let (tx, rx) = mpsc::channel(buffer);
   148→        (Self { sender: tx }, rx)
   149→    }
   150→}
   151→
   152→#[async_trait::async_trait]
   153→impl EventPublisher for InMemoryPublisher {
   154→    #[instrument(skip(self, envelope))]
   155→    async fn publish(&self, envelope: EventEnvelope) -> Result<PublishAck> {
   156→        self.sender
   157→            .send(envelope)
   158→            .await
   159→            .map_err(|_| PublisherError::ChannelClosed)?;
   160→        Ok(PublishAck { broker_sequence: None })
   161→    }
   162→}
   163→
   164→/// Production NATS publisher.
   165→pub struct NatsPublisher {
   166→    client: async_nats::Client,
   167→    subject: String,
   168→    /// Buffer to offer some back-pressure. tower::buffer will
   169→    /// spawn background tasks to flush to NATS.
   170→    pipeline: tower::buffer::Buffer<EventEnvelope, Result<PublishAck>>,
   171→}
   172→
   173→impl NatsPublisher {
   174→    /// Connects to a NATS server using TLS and auth token.
   175→    ///
   176→    /// # Arguments
   177→    /// * `url` – nats:// or tls:// URL
   178→    /// * `subject` – target subject (topic) where events are sent
   179→    /// * `auth_token` – JWT or static token configured server-side
   180→    pub async fn with_tls(
   181→        url: &str,
   182→        subject: impl Into<String>,
   183→        auth_token: Option<String>,
   184→    ) -> Result<Self> {
   185→        // Build connect options
   186→        let mut opts = ConnectOptions::new();
   187→        if let Some(token) = auth_token {
   188→            opts = opts.auth_token(token);
   189→        }
   190→
   191→        // Enable TLS automatically when url scheme is tls://
   192→        let client = opts.connect(url).await?;
   193→
   194→        let subject = subject.into();
   195→        // Create a tower service that serializes and ships the message
   196→        let svc = tower::service_fn({
   197→            let client = client.clone();
   198→            let subject = subject.clone();
   199→            move |env: EventEnvelope| {
   200→                let client = client.clone();
   201→                let subject = subject.clone();
   202→                async move {
   203→                    // encode to json
   204→                    let payload = serde_json::to_vec(&env)?;
   205→                    trace!(%subject, size = payload.len(), "Publishing to NATS");
   206→                    let ack = client.publish(subject, payload.into()).await?;
   207→                    Ok(PublishAck {
   208→                        broker_sequence: ack.map(|a| a.sequence),
   209→                    })
   210→                }
   211→            }
   212→        });
   213→
   214→        // Buffer with sensible defaults (in-memory)
   215→        let buffer = tower::buffer::Buffer::new(svc, 256);
   216→
   217→        Ok(Self {
   218→            client,
   219→            subject,
   220→            pipeline: buffer,
   221→        })
   222→    }
   223→
   224→    /// Flush buffered messages (best effort)
   225→    pub async fn flush(&self) -> Result<()> {
   226→        self.client.flush().await.map_err(Into::into)
   227→    }
   228→}
   229→
   230→#[async_trait::async_trait]
   231→impl EventPublisher for NatsPublisher {
   232→    #[instrument(skip(self))]
   233→    async fn publish(&self, envelope: EventEnvelope) -> Result<PublishAck> {
   234→        self.pipeline.clone().oneshot(envelope).await?
   235→    }
   236→}
