   238→/// Builder that knows how to instantiate an `EventPublisher`
   239→/// according to environment configuration.  This keeps details
   240→/// such as local vs integration test conditions in one place.
   241→pub struct EventPublisherFactory;
   242→
   243→impl EventPublisherFactory {
   244→    /// Build from standard `EDUPULSE_*` environment variables.
   245→    ///
   246→    ///  - `EDUPULSE_EVENT_BROKER_URL`
   247→    ///  - `EDUPULSE_EVENT_BROKER_SUBJECT`
   248→    ///  - `EDUPULSE_EVENT_BROKER_TOKEN`
   249→    ///
   250→    /// If the variables are not set, falls back to an in-memory publisher.
   251→    pub async fn build_from_env() -> Box<dyn EventPublisher> {
   252→        match (
   253→            std::env::var("EDUPULSE_EVENT_BROKER_URL").ok(),
   254→            std::env::var("EDUPULSE_EVENT_BROKER_SUBJECT").ok(),
   255→        ) {
   256→            (Some(url), Some(subject)) => {
   257→                let token = std::env::var("EDUPULSE_EVENT_BROKER_TOKEN").ok();
   258→                match NatsPublisher::with_tls(&url, subject, token).await {
   259→                    Ok(p) => {
   260→                        debug!("Using NATS event publisher ({url})");
   261→                        Box::new(p)
   262→                    }
   263→                    Err(e) => {
   264→                        error!(error = %e, "Failed to create NATS publisher, falling back to in-memory");
   265→                        Self::in_memory().0.into()
   266→                    }
   267→                }
   268→            }
   269→            _ => {
   270→                warn!("No broker env vars found, using in-memory event publisher");
   271→                Self::in_memory().0.into()
   272→            }
   273→        }
   274→    }
   275→
   276→    pub fn in_memory() -> (Box<dyn EventPublisher>, mpsc::Receiver<EventEnvelope>) {
   277→        let (p, rx) = InMemoryPublisher::new(256);
   278→        (Box::new(p), rx)
   279→    }
   280→}
