     2→//! src/module_60.rs
     3→//!
     4→//! Core business-logic for creating “learning pulses” and handling student
     5→//! replies.  All write-operations emit strongly-typed domain events that are
     6→//! published to the async message broker (e.g. NATS, RabbitMQ or Kafka) so that
     7→//! downstream services—plagiarism checker, notification fan-out, analytics,
     8→//! etc.—can react without coupling.
     9→//!
    10→//! The module follows a classical Service/Repository split and is completely
    11→//! unit-testable thanks to its fully mockable trait interfaces.
    12→//!
    13→//! # Examples
    14→//! ```no_run
    15→//! use edupulse_live::pulse::service::{PulseService, ServiceConfig};
    16→//! use edupulse_live::pulse::repository::InMemoryPulseRepository;
    17→//! use edupulse_live::infra::broker::NatsPublisher;
    18→//! use std::sync::Arc;
    19→//! use uuid::Uuid;
    20→//!
    21→//! #[tokio::main]
    22→//! async fn main() -> anyhow::Result<()> {
    23→//!     let repo = Arc::new(InMemoryPulseRepository::default());
    24→//!     let publisher = Arc::new(NatsPublisher::connect("nats://localhost:4222").await?);
    25→//!
    26→//!     let svc = PulseService::new(ServiceConfig::default(), repo, publisher);
    27→//!
    28→//!     let teacher_id = Uuid::new_v4();
    29→//!     let pulse_id = svc
    30→//!         .create_pulse(teacher_id, "Explain async/await in Rust".into())
    31→//!         .await?;
    32→//!
    33→//!     let student_id = Uuid::new_v4();
    34→//!     svc.reply_to_pulse(pulse_id, student_id, "Here is my explanation…".into())
    35→//!         .await?;
    36→//!     Ok(())
    37→//! }
    38→//! ```
    39→
    40→use async_trait::async_trait;
    41→use chrono::{DateTime, Utc};
    42→use serde::{Deserialize, Serialize};
    43→use std::sync::Arc;
    44→use thiserror::Error;
    45→use tokio::time::{sleep, Duration};
    46→use uuid::Uuid;
    47→
    48→/// Unique identifier wrappers make the type system work for us
    49→#[derive(
    50→    Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize, derive_more::Display,
    51→)]
    52→pub struct UserId(Uuid);
    53→
    54→#[derive(
    55→    Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize, derive_more::Display,
    56→)]
    57→pub struct PulseId(Uuid);
    58→
    59→impl From<Uuid> for UserId {
    60→    fn from(v: Uuid) -> Self {
    61→        Self(v)
    62→    }
    63→}
    64→impl From<Uuid> for PulseId {
    65→    fn from(v: Uuid) -> Self {
    66→        Self(v)
    67→    }
    68→}
    69→
    70→/// Domain-layer entity: a *Learning Pulse* authored by a teacher.
    71→#[derive(Debug, Clone, Serialize, Deserialize)]
    72→pub struct Pulse {
    73→    pub id: PulseId,
    74→    pub author_id: UserId,
    75→    pub prompt: String,
    76→    pub created_at: DateTime<Utc>,
    77→    pub replies: Vec<Reply>,
    78→}
    79→
    80→/// Student reply to a pulse.
    81→#[derive(Debug, Clone, Serialize, Deserialize)]
    82→pub struct Reply {
    83→    pub id: Uuid,
    84→    pub pulse_id: PulseId,
    85→    pub student_id: UserId,
    86→    pub content: String,
    87→    pub created_at: DateTime<Utc>,
    88→}
    89→
    90→/// Strongly-typed domain events emitted by the service.
    91→///
    92→/// Downstream services subscribe to the `subject()` and deserialize payloads
    93→/// back into these exact structures (thanks to `serde`).
    94→#[derive(Debug, Clone, Serialize, Deserialize)]
    95→#[serde(tag = "type", rename_all = "snake_case")]
    96→pub enum PulseDomainEvent {
    97→    PulseCreated {
    98→        pulse_id: PulseId,
    99→        author_id: UserId,
   100→        prompt: String,
   101→        created_at: DateTime<Utc>,
   102→    },
   103→    PulseReplied {
   104→        pulse_id: PulseId,
   105→        reply_id: Uuid,
   106→        student_id: UserId,
   107→        created_at: DateTime<Utc>,
   108→    },
   109→}
   110→
   111→impl PulseDomainEvent {
   112→    pub fn subject(&self) -> &'static str {
   113→        match self {
   114→            PulseDomainEvent::PulseCreated { .. } => "pulse.created",
   115→            PulseDomainEvent::PulseReplied { .. } => "pulse.replied",
   116→        }
   117→    }
   118→}
