   120→/* ---------- Repository Layer ---------- */
   121→
   122→#[async_trait]
   123→pub trait PulseRepository: Send + Sync {
   124→    async fn insert(&self, pulse: Pulse) -> Result<(), RepositoryError>;
   125→    async fn find(&self, id: PulseId) -> Result<Option<Pulse>, RepositoryError>;
   126→    async fn upsert(&self, pulse: Pulse) -> Result<(), RepositoryError>;
   127→}
   128→
   129→#[derive(Debug, Error)]
   130→pub enum RepositoryError {
   131→    #[error("database unavailable")]
   132→    Unavailable,
   133→    #[error("anyhow: {0}")]
   134→    Other(#[from] anyhow::Error),
   135→}
