   137→/// A simple, thread-safe in-memory implementation useful for unit tests.
   138→/// Not optimized for production—replace with Postgres, MongoDB, etc.
   139→#[derive(Default)]
   140→pub struct InMemoryPulseRepository {
   141→    store: parking_lot::RwLock<std::collections::HashMap<PulseId, Pulse>>,
   142→}
   143→
   144→#[async_trait]
   145→impl PulseRepository for InMemoryPulseRepository {
   146→    async fn insert(&self, pulse: Pulse) -> Result<(), RepositoryError> {
   147→        let mut guard = self.store.write();
   148→        guard.insert(pulse.id, pulse);
   149→        Ok(())
   150→    }
   151→
   152→    async fn find(&self, id: PulseId) -> Result<Option<Pulse>, RepositoryError> {
   153→        let guard = self.store.read();
   154→        Ok(guard.get(&id).cloned())
   155→    }
   156→
   157→    async fn upsert(&self, pulse: Pulse) -> Result<(), RepositoryError> {
   158→        let mut guard = self.store.write();
   159→        guard.insert(pulse.id, pulse);
   160→        Ok(())
   161→    }
   162→}
   163→
   164→/* ---------- Message Broker Abstraction ---------- */
   165→
   166→#[async_trait]
   167→pub trait EventPublisher: Send + Sync {
   168→    async fn publish<E>(&self, subject: &str, event: &E) -> Result<(), PublishError>
   169→    where
   170→        E: Serialize + Send + Sync;
   171→}
   172→
   173→#[derive(Debug, Error)]
   174→pub enum PublishError {
   175→    #[error("connection lost")]
   176→    LostConnection,
   177→    #[error("serialization failed: {0}")]
   178→    Serde(#[from] serde_json::Error),
   179→    #[error("anyhow: {0}")]
   180→    Other(#[from] anyhow::Error),
   181→}
