   183→/* Example implementation using NATS -------------------------------------- */
   184→pub mod nats_impl {
   185→    use super::*;
   186→    use async_nats::{self, Client as NatsClient};
   187→
   188→    pub struct NatsPublisher {
   189→        client: NatsClient,
   190→    }
   191→
   192→    impl NatsPublisher {
   193→        pub async fn connect(url: &str) -> anyhow::Result<Self> {
   194→            let client = async_nats::connect(url).await?;
   195→            Ok(Self { client })
   196→        }
   197→    }
   198→
   199→    #[async_trait]
   200→    impl EventPublisher for NatsPublisher {
   201→        async fn publish<E>(&self, subject: &str, event: &E) -> Result<(), PublishError>
   202→        where
   203→            E: Serialize + Send + Sync,
   204→        {
   205→            let payload = serde_json::to_vec(event)?;
   206→            self.client
   207→                .publish(subject.into(), payload.into())
   208→                .await
   209→                .map_err(|_| PublishError::LostConnection)?;
   210→            Ok(())
   211→        }
   212→    }
   213→}
   214→/* ------------------------------------------------------------------------ */
   215→
   216→/* ---------- Service Layer ---------------------------------------------- */
   217→
   218→/// Configuration knobs for the `PulseService`. They come with sensible
   219→/// production defaults that can be tweaked at runtime.
   220→#[derive(Debug, Clone)]
   221→pub struct ServiceConfig {
   222→    /// Artificial write-latency useful during early load-testing; set to zero
   223→    /// in production.
   224→    pub simulated_db_latency: Duration,
   225→}
   226→
   227→impl Default for ServiceConfig {
   228→    fn default() -> Self {
