   230→            simulated_db_latency: Duration::from_millis(0),
   231→        }
   232→    }
   233→}
   234→
   235→#[derive(Debug, Error)]
   236→pub enum ServiceError {
   237→    #[error("repository error: {0}")]
   238→    Repo(#[from] RepositoryError),
   239→    #[error("event publication failed: {0}")]
   240→    Publish(#[from] PublishError),
   241→    #[error("pulse not found")]
