   245→/// The façade consumed by REST handlers, GraphQL resolvers, background jobs,
   246→/// etc.  All functions are `async` and return rich error types.
   247→///
   248→/// The struct is `Clone` because it only contains `Arc` handles.
   249→#[derive(Clone)]
   250→pub struct PulseService<R, P>
   251→where
   252→    R: PulseRepository,
   253→    P: EventPublisher,
   254→{
   255→    cfg: ServiceConfig,
   256→    repo: Arc<R>,
