   259→
   260→impl<R, P> PulseService<R, P>
   261→where
   262→    R: PulseRepository,
   263→    P: EventPublisher,
   264→{
   265→    pub fn new(cfg: ServiceConfig, repo: Arc<R>, publisher: Arc<P>) -> Self {
