   272→
   273→    /// Teacher creates a new learning pulse.
   274→    pub async fn create_pulse(
   275→        &self,
   276→        author_id: Uuid,
   277→        prompt: String,
   278→    ) -> Result<PulseId, ServiceError> {
   279→        // Simulate DB latency if configured
   280→        if self.cfg.simulated_db_latency != Duration::ZERO {
   281→            sleep(self.cfg.simulated_db_latency).await;
   282→        }
   283→
   284→        let pulse = Pulse {
   285→            id: PulseId(Uuid::new_v4()),
   286→            author_id: UserId(author_id),
   287→            prompt: prompt.clone(),
   288→            created_at: Utc::now(),
   289→            replies: Vec::new(),
   290→        };
   291→
   292→        self.repo.insert(pulse.clone()).await?;
   293→
   294→        let event = PulseDomainEvent::PulseCreated {
   295→            pulse_id: pulse.id,
   296→            author_id: pulse.author_id,
   297→            prompt,
   298→            created_at: pulse.created_at,
   299→        };
   300→        self.publisher.publish(event.subject(), &event).await?;
   301→
   302→        Ok(pulse.id)
   303→    }
   304→
   305→    /// Student replies to existing pulse.
   306→    pub async fn reply_to_pulse(
   307→        &self,
   308→        pulse_id: PulseId,
   309→        student_id: Uuid,
   310→        content: String,
   311→    ) -> Result<Uuid, ServiceError> {
   312→        let mut pulse = self
   313→            .repo
   314→            .find(pulse_id)
   315→            .await?
   316→            .ok_or(ServiceError::PulseNotFound)?;
   317→
   318→        let reply = Reply {
   319→            id: Uuid::new_v4(),
   320→            pulse_id,
   321→            student_id: UserId(student_id),
   322→            content,
   323→            created_at: Utc::now(),
   324→        };
   325→        pulse.replies.push(reply.clone());
   326→        self.repo.upsert(pulse).await?;
   327→
   328→        let event = PulseDomainEvent::PulseReplied {
   329→            pulse_id,
   330→            reply_id: reply.id,
   331→            student_id: reply.student_id,
   332→            created_at: reply.created_at,
   333→        };
   334→        self.publisher.publish(event.subject(), &event).await?;
   335→
   336→        Ok(reply.id)
   337→    }
   338→}
