     2→//! src/module_20.rs
     3→//!
     4→//! Event-sourcing infrastructure for **EduPulse Live – Event-Driven Social Learning Hub**.
     5→//!
     6→//! This module contains everything required to create, persist, and dispatch
     7→//! immutable domain events in a fully-async, **Tokio** powered context.  The
     8→//! code is designed to be reusable across bounded contexts and hides the
     9→//! mechanics of the message broker behind a lightweight `EventBus` façade.
    10→//!
    11→//! Production-quality concerns included:
    12→//!   • Proper error propagation (`thiserror`)  
    13→//!   • Database integration (`sqlx` w/ compile-time SQL checks)  
    14→//!   • Structured, versioned events with serialization guards (`serde`)  
    15→//!   • Broadcast-based in-process fan-out with back-pressure awareness  
    16→//!   • Cancellation-safe, async/await-friendly API
    17→//!
    18→//! NOTE: In production, the `EventBus` would be backed by Kafka/RabbitMQ/Redis.
    19→//!       For the sake of testability and single-crate compilation the example
    20→//!       uses `tokio::sync::broadcast`.
    21→
    22→#![allow(clippy::module_name_repetitions)]
    23→
    24→use std::{
    25→    fmt,
    26→    sync::Arc,
    27→};
    28→
    29→use async_trait::async_trait;
    30→use chrono::{DateTime, Utc};
    31→use futures::FutureExt;
    32→use serde::{Deserialize, Serialize};
    33→use sqlx::{PgPool, Postgres, QueryBuilder};
    34→use thiserror::Error;
    35→use tokio::sync::broadcast;
    36→use uuid::Uuid;
    37→
    38→/// All domain events must be wrapped inside an `EventEnvelope`.  
    39→/// The envelope guarantees a stable schema for persistence and transport.
    40→#[derive(Debug, Clone, Serialize, Deserialize)]
    41→pub struct EventEnvelope {
    42→    /// Unique event id (ULID would also be appropriate).
    43→    pub id:           Uuid,
    44→    /// Type discriminator used by consumers / metrics.
    45→    pub event_type:   String,
    46→    /// UTC timestamp at event creation (not persistence).
    47→    pub occurred_at:  DateTime<Utc>,
    48→    /// Optional correlation id to group together causally related events.
    49→    pub correlation:  Option<Uuid>,
    50→    /// Opaque payload containing domain-specific data.
    51→    pub payload:      serde_json::Value,
    52→    /// Schema version for data migrations / evolution.
    53→    pub version:      i32,
    54→}
    55→
    56→impl EventEnvelope {
    57→    /// Creates an envelope from any `DomainEvent` implementor.
    58→    pub fn new<E: DomainEvent>(event: &E, correlation: Option<Uuid>) -> Result<Self, EventError> {
    59→        let payload = serde_json::to_value(event)
    60→            .map_err(EventError::Serialization)?;
    61→        Ok(Self {
    62→            id: Uuid::new_v4(),
    63→            event_type: event.event_type().to_owned(),
    64→            occurred_at: Utc::now(),
    65→            correlation,
    66→            payload,
    67→            version: E::SCHEMA_VERSION,
    68→        })
    69→    }
    70→}
    71→
    72→/// Marker trait implemented by all strongly-typed, serializable domain events.
    73→#[async_trait]
    74→pub trait DomainEvent: Serialize + Send + Sync {
    75→    /// Consumers rely on this string discriminator.
    76→    fn event_type(&self) -> &'static str;
    77→    /// Increment when breaking changes occur.
    78→    const SCHEMA_VERSION: i32 = 1;
    79→}
    80→
    81→/// ---------------------------------------------------------------------------
    82→/// Example events occurring inside the EduPulse Live domain
    83→/// ---------------------------------------------------------------------------
    84→
    85→#[derive(Debug, Serialize, Deserialize)]
    86→pub struct LessonPublished {
    87→    pub lesson_id:  Uuid,
    88→    pub teacher_id: Uuid,
    89→    pub title:      String,
    90→}
    91→
    92→#[async_trait]
    93→impl DomainEvent for LessonPublished {
    94→    fn event_type(&self) -> &'static str { "lesson.published" }
    95→}
    96→
    97→#[derive(Debug, Serialize, Deserialize)]
    98→pub struct QuizSubmitted {
    99→    pub quiz_id:   Uuid,
   100→    pub student_id: Uuid,
   101→    pub score:      f32,
   102→}
   103→
   104→#[async_trait]
   105→impl DomainEvent for QuizSubmitted {
   106→    fn event_type(&self) -> &'static str { "quiz.submitted" }
   107→}
   108→
   109→/// ---------------------------------------------------------------------------
   110→/// Error handling
   111→/// ---------------------------------------------------------------------------
   112→
   113→#[derive(Debug, Error)]
   114→pub enum EventError {
   115→    #[error("serialization failure: {0}")]
   116→    Serialization(#[from] serde_json::Error),
   117→
   118→    #[error("broadcast channel error: {0}")]
   119→    Channel(#[from] broadcast::error::SendError<Arc<EventEnvelope>>),
   120→
   121→    #[error("sqlx error: {0}")]
   122→    Sqlx(#[from] sqlx::Error),
   123→}
   124→
   125→/// Convenience alias used by callers that don't care about the concrete error.
   126→pub type Result<T, E = EventError> = std::result::Result<T, E>;
   127→
   128→/// ---------------------------------------------------------------------------
   129→/// Event store (PostgreSQL)
   130→/// ---------------------------------------------------------------------------
   131→
   132→/// Persists immutable events in an append-only table.
   133→///
   134→/// SQL:
   135→/// ```sql
   136→/// CREATE TABLE IF NOT EXISTS event_store (
   137→///     id            UUID PRIMARY KEY,
   138→///     event_type    TEXT NOT NULL,
   139→///     occurred_at   TIMESTAMPTZ NOT NULL,
   140→///     correlation   UUID NULL,
   141→///     payload       JSONB NOT NULL,
   142→///     version       INT  NOT NULL
   143→/// );
   144→/// ```
   145→#[derive(Clone)]
   146→pub struct PgEventStore {
   147→    pool: PgPool,
   148→}
   149→
   150→impl PgEventStore {
   151→    pub fn new(pool: PgPool) -> Self {
   152→        Self { pool }
   153→    }
   154→
   155→    /// Persist a single envelope inside a transactional boundary.
   156→    pub async fn persist(&self, env: &EventEnvelope) -> Result<()> {
   157→        QueryBuilder::<Postgres>::new(
   158→            "INSERT INTO event_store (id, event_type, occurred_at, correlation, payload, version)",
   159→        )
   160→        .push_values(
   161→            std::iter::once(env),
   162→            |mut b, e| {
   163→                b.push_bind(e.id)
   164→                    .push_bind(&e.event_type)
   165→                    .push_bind(e.occurred_at)
   166→                    .push_bind(e.correlation)
   167→                    .push_bind(&e.payload)
   168→                    .push_bind(e.version);
   169→            },
   170→        )
   171→        .build()
   172→        .execute(&self.pool)
   173→        .await?;
   174→
   175→        Ok(())
   176→    }
   177→}
   178→
   179→/// ---------------------------------------------------------------------------
   180→/// In-process event bus
   181→/// ---------------------------------------------------------------------------
   182→
   183→const BROADCAST_BUFFER: usize = 256;
   184→
   185→#[derive(Clone)]
   186→pub struct EventBus {
   187→    tx: broadcast::Sender<Arc<EventEnvelope>>,
   188→}
   189→
   190→impl EventBus {
   191→    /// Creates a new, bounded broadcast bus.
   192→    pub fn new() -> Self {
   193→        let (tx, _) = broadcast::channel(BROADCAST_BUFFER);
   194→        Self { tx }
   195→    }
   196→
   197→    /// Publish an envelope to all subscribers (fire-and-forget).
   198→    pub fn dispatch(&self, env: Arc<EventEnvelope>) -> Result<()> {
   199→        self.tx.send(env)?;
   200→        Ok(())
   201→    }
   202→
   203→    /// Subscribe to all events.  Each subscriber has an independent cursor.
   204→    pub fn subscribe(&self) -> broadcast::Receiver<Arc<EventEnvelope>> {
   205→        self.tx.subscribe()
   206→    }
   207→}
   208→
   209→/// ---------------------------------------------------------------------------
   210→/// High-level façade combining store + bus
   211→/// ---------------------------------------------------------------------------
   212→
   213→#[derive(Clone)]
   214→pub struct EventDispatcher {
   215→    store: PgEventStore,
   216→    bus:   EventBus,
   217→}
   218→
   219→impl EventDispatcher {
   220→    pub fn new(store: PgEventStore, bus: EventBus) -> Self {
