     2→//! src/module_6.rs
     3→//!
     4→//! Event-sourcing audit-trail and GDPR-erase utilities used by several
     5→//! EduPulse Live services.  The module is designed so that other crates
     6→//! (web API, background workers, analytics pipeline, …) can depend on a
     7→//! single abstraction while swapping out storage back-ends if necessary.
     8→//!
     9→//! Compile with the following feature flags enabled in `Cargo.toml`:
    10→//!
    11→//! ```toml
    12→//! [dependencies]
    13→//! tokio      = { version = "1", features = ["rt-multi-thread", "macros"] }
    14→//! sqlx       = { version = "0.7", features = ["runtime-tokio-rustls", "postgres", "chrono", "uuid", "json"] }
    15→//! serde      = { version = "1", features = ["derive"] }
    16→//! serde_json = "1"
    17→//! chrono     = { version = "0.4", features = ["serde"] }
    18→//! uuid       = { version = "1", features = ["serde", "v4"] }
    19→//! async-trait = "0.1"
    20→//! anyhow     = "1"
    21→//! thiserror  = "1"
    22→//! tracing    = "0.1"
    23→//! ```
    24→//!
    25→//! NOTE: The module purposely never panics in normal operation; all
    26→//!       failures are surfaced through `Result` so that upper layers can
    27→//!       respond gracefully (retry, circuit-break, alerting, …).
    28→
    29→use std::env;
    30→use std::fmt;
    31→
    32→use async_trait::async_trait;
    33→use chrono::{DateTime, Utc};
    34→use serde::{Deserialize, Serialize};
    35→use serde_json::Value as JsonValue;
    36→use sqlx::{postgres::PgRow, PgPool, Row};
    37→use thiserror::Error;
    38→use tracing::{error, info, instrument};
    39→use uuid::Uuid;
    40→
    41→/// A high-level description of all domain events the system cares about.
    42→/// New application features SHOULD extend this enum instead of inventing ad-hoc
    43→/// JSON structures in order to keep the audit log queryable.
    44→///
    45→/// The enum is (de)serialised to/from snake_case strings so that DB queries
    46→/// remain ergonomic and dashboards can group by `event_type`.
    47→#[derive(Debug, Clone, Serialize, Deserialize, sqlx::Type)]
    48→#[serde(rename_all = "snake_case")]
    49→#[sqlx(type_name = "VARCHAR")]
    50→pub enum DomainEventType {
    51→    LessonPublished,
    52→    QuizSubmitted,
    53→    PeerFeedbackGiven,
    54→    BadgeAwarded,
    55→    PaymentProcessed,
    56→    LearningPulseCreated,
    57→    LearningPulseReplied,
    58→}
    59→
    60→/// A single, immutable audit log record.
    61→///
    62→///  • `event_id`      globally unique (ordered by `created_at` for convenience)  
    63→///  • `aggregate_id`  the main entity the event acts upon (user, course, …)  
    64→///  • `payload`       arbitrary JSON, validated at application boundaries  
    65→///
    66→/// The actual binary representation in Postgres is a row in table
    67→/// `audit_events` (see the migration in `migrations/20230720114523_audit.sql`)
    68→#[derive(Debug, Clone, Serialize, Deserialize)]
    69→pub struct AuditEvent {
    70→    pub event_id: Uuid,
    71→    pub aggregate_id: Uuid,
    72→    pub event_type: DomainEventType,
    73→    pub payload: JsonValue,
    74→    pub created_at: DateTime<Utc>,
    75→}
    76→
    77→impl fmt::Display for AuditEvent {
    78→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
    79→        write!(
    80→            f,
    81→            "{} – {:?} – {}",
    82→            self.event_id, self.event_type, self.created_at
    83→        )
    84→    }
    85→}
    86→
    87→/// Top-level error type returned by this module.  Using a single error enum
    88→/// (rather than scattering opaque `anyhow::Error`s) makes pattern-matching
    89→/// in callers easier and metrics aggregation cleaner.
    90→#[derive(Debug, Error)]
    91→pub enum EventStoreError {
    92→    #[error("database connection error: {0:?}")]
    93→    Connection(#[from] sqlx::Error),
    94→
    95→    #[error("serialization error: {0:?}")]
    96→    Serde(#[from] serde_json::Error),
    97→
    98→    #[error("attempt to erase non-existing user {0}")]
    99→    UnknownUser(Uuid),
   100→
   101→    #[error("unexpected error: {0}")]
   102→    Other(#[from] anyhow::Error),
   103→}
   104→
   105→/// Abstraction for writing/reading events.  The trait is intentionally narrow
   106→/// so that adapters for DynamoDB, Kafka-compacted topics, or filesystem
   107→/// snapshots can be added later with minimal friction.
   108→#[async_trait]
   109→pub trait EventStore: Send + Sync {
   110→    async fn append_event(&self, event: &AuditEvent) -> Result<(), EventStoreError>;
   111→    async fn fetch_events_by_aggregate(
   112→        &self,
   113→        aggregate_id: Uuid,
   114→    ) -> Result<Vec<AuditEvent>, EventStoreError>;
   115→    /// GDPR-style erase.  The default behaviour is pseudonymisation:
   116→    /// personal fields in the JSON payload are stripped/replaced while
   117→    /// keeping aggregate-level metadata for analytics/regulatory audits.
   118→    async fn pseudonymise_user(
   119→        &self,
   120→        user_id: Uuid,
   121→        pseudonym: &str,
   122→    ) -> Result<(), EventStoreError>;
   123→}
   124→
   125→/// Postgres 15 implementation.  Requires the following DDL:
   126→///
   127→/// ```sql
   128→/// CREATE TABLE IF NOT EXISTS audit_events (
   129→///     event_id     UUID PRIMARY KEY,
   130→///     aggregate_id UUID NOT NULL,
   131→///     event_type   VARCHAR NOT NULL,
   132→///     payload      JSONB NOT NULL,
   133→///     created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
   134→/// );
   135→/// CREATE INDEX IF NOT EXISTS idx_audit_aggregate
   136→///     ON audit_events (aggregate_id);
   137→/// CREATE INDEX IF NOT EXISTS idx_audit_event_type
   138→///     ON audit_events (event_type);
   139→/// ```
   140→pub struct PgEventStore {
   141→    pool: PgPool,
   142→}
   143→
   144→impl PgEventStore {
   145→    /// Reads standard environment variables (e.g., `DATABASE_URL`) if `pool`
   146→    /// is not supplied.  Callers can also pass a pre-initialised `PgPool`
   147→    /// obtained from an application-wide connection manager.
   148→    pub async fn new(pool: Option<PgPool>) -> Result<Self, EventStoreError> {
   149→        match pool {
   150→            Some(p) => Ok(Self { pool: p }),
   151→            None => {
   152→                let db_url = env::var("DATABASE_URL")
   153→                    .map_err(|_| anyhow::anyhow!("DATABASE_URL env var not set"))?;
   154→                let max_conns: u32 =
   155→                    env::var("DATABASE_MAX_CONNS").unwrap_or_else(|_| "8".into()).parse().unwrap();
   156→                let pool = PgPool::builder()
   157→                    .max_size(max_conns)
   158→                    .build(&db_url)
   159→                    .await?;
   160→                Ok(Self { pool })
   161→            }
   162→        }
   163→    }
   164→}
   165→
   166→#[async_trait]
   167→impl EventStore for PgEventStore {
   168→    #[instrument(skip_all, fields(event_id=%event.event_id))]
   169→    async fn append_event(&self, event: &AuditEvent) -> Result<(), EventStoreError> {
   170→        sqlx::query(
   171→            r#"
   172→            INSERT INTO audit_events (event_id, aggregate_id, event_type, payload, created_at)
   173→            VALUES ($1, $2, $3, $4, $5)
   174→            "#,
   175→        )
   176→        .bind(event.event_id)
   177→        .bind(event.aggregate_id)
   178→        .bind(event.event_type.clone())
   179→        .bind(&event.payload)
   180→        .bind(event.created_at)
   181→        .execute(&self.pool)
   182→        .await?;
   183→
   184→        info!(%event.event_id, "event persisted");
   185→        Ok(())
   186→    }
   187→
   188→    #[instrument(skip_all, fields(aggregate_id=%aggregate_id))]
   189→    async fn fetch_events_by_aggregate(
   190→        &self,
   191→        aggregate_id: Uuid,
   192→    ) -> Result<Vec<AuditEvent>, EventStoreError> {
   193→        let rows = sqlx::query(
   194→            r#"
   195→            SELECT event_id, aggregate_id, event_type, payload, created_at
   196→            FROM audit_events
   197→            WHERE aggregate_id = $1
   198→            ORDER BY created_at ASC
   199→            "#,
   200→        )
   201→        .bind(aggregate_id)
   202→        .fetch_all(&self.pool)
   203→        .await?;
   204→
   205→        let events = rows.into_iter().map(row_to_event).collect::<Result<_, _>>()?;
   206→        Ok(events)
   207→    }
   208→
   209→    /// Iterates through *all* events where `aggregate_id = user_id`, then
   210→    /// transforms the JSON payload via `pseudonymise_payload`.  Runs inside a
   211→    /// `BEGIN … COMMIT` block to guarantee atomicity.
   212→    #[instrument(skip_all, fields(user_id=%user_id))]
   213→    async fn pseudonymise_user(
   214→        &self,
   215→        user_id: Uuid,
   216→        pseudonym: &str,
   217→    ) -> Result<(), EventStoreError> {
   218→        let mut tx = self.pool.begin().await?;
   219→
