     2→//! src/module_64.rs
     3→//!
     4→//! “Event-Bus” abstraction + Kafka implementation for EduPulse Live.
     5→//!
     6→//! The module provides:
     7→//! 1. A `DomainEvent` enum that captures the most common events emitted by the core API.
     8→//! 2. An `EventEnvelope` wrapper with metadata useful for audit-logging and GDPR erase trails.
     9→//! 3. An `EventBus` trait with async `publish` / `subscribe` operations.
    10→//! 4. A production-ready Kafka implementation (`KafkaEventBus`) using `rdkafka`.
    11→//! 5. A small “audit trail” consumer that persists raw events into PostgreSQL via `sqlx`.
    12→//!
    13→//! The code purposefully hides low-level details behind traits, enabling unit tests to depend on
    14→//! in-memory stubs while production builds can toggle the `kafka`/`postgres` features.
    15→
    16→use std::time::Duration;
    17→
    18→use async_trait::async_trait;
    19→use chrono::{DateTime, Utc};
    20→use futures::{Stream, StreamExt};
    21→use rdkafka::{
    22→    consumer::{CommitMode, Consumer, StreamConsumer},
    23→    producer::{FutureProducer, FutureRecord},
    24→    ClientConfig, Message,
    25→};
    26→use serde::{Deserialize, Serialize};
    27→use thiserror::Error;
    28→use tokio::task::JoinHandle;
    29→use tracing::{debug, error, info, instrument};
    30→use uuid::Uuid;
    31→
    32→/// Kafka topic used for system-wide domain events.
    33→pub const DOMAIN_EVENT_TOPIC: &str = "edu_pulse_domain_events";
    34→
    35→/// Shared error type for the event layer.
    36→#[derive(Debug, Error)]
    37→pub enum EventBusError {
    38→    #[error("serialization error: {0}")]
    39→    Serialization(#[from] serde_json::Error),
    40→
    41→    #[error("kafka error: {0}")]
    42→    Kafka(#[from] rdkafka::error::KafkaError),
    43→
    44→    #[error("sqlx error: {0}")]
    45→    #[cfg(feature = "postgres")]
    46→    Sqlx(#[from] sqlx::Error),
    47→
    48→    #[error("stream closed")]
    49→    StreamClosed,
    50→
    51→    #[error("unknown error")]
    52→    Unknown,
    53→}
    54→
    55→/// Metadata attached to every `DomainEvent` when sent across the wire.
    56→///
    57→/// Keeps the envelope format extensible while allowing GDPR-compatible deletes
    58→/// through `subject_id`.
    59→#[derive(Debug, Clone, Serialize, Deserialize)]
    60→pub struct EventEnvelope<T: Serialize + for<'de> Deserialize<'de>> {
    61→    pub id: Uuid,
    62→    pub subject_id: Uuid,
    63→    pub created_at: DateTime<Utc>,
    64→    pub payload: T,
    65→}
    66→
    67→/// High-level domain events emitted by EduPulse Live.
    68→///
    69→/// NOTE: Each variant must remain backward-compatible once published.
    70→/// Use additive changes only; never reorder or remove existing variants.
    71→#[derive(Debug, Clone, Serialize, Deserialize)]
    72→#[serde(tag = "type", content = "data")]
    73→#[non_exhaustive]
    74→pub enum DomainEvent {
    75→    LessonPublished {
    76→        lesson_id: Uuid,
    77→        author_id: Uuid,
    78→        title: String,
    79→    },
    80→    LearningPulseCreated {
    81→        pulse_id: Uuid,
    82→        teacher_id: Uuid,
    83→        course_id: Uuid,
    84→        prompt: String,
    85→        expires_at: DateTime<Utc>,
    86→    },
    87→    PulseSubmissionReceived {
    88→        submission_id: Uuid,
    89→        pulse_id: Uuid,
    90→        student_id: Uuid,
    91→        artefact_url: String,
    92→    },
    93→    QuizSubmitted {
    94→        quiz_id: Uuid,
    95→        attempt_id: Uuid,
    96→        student_id: Uuid,
    97→        score: f32,
    98→    },
    99→    BadgeAwarded {
   100→        badge_id: Uuid,
   101→        recipient_id: Uuid,
   102→        reason: String,
   103→    },
   104→}
   105→
   106→/// Asynchronous, streaming event bus abstraction.
   107→///
   108→/// `publish` pushes an event to the broker and resolves when the broker acks.
   109→/// `subscribe` yields a *cold* stream that starts delivering events once awaited.
   110→///
   111→/// Cloneable by design: cloning a bus creates another handle to the same
   112→/// backend (producer + consumer group).
   113→#[async_trait]
   114→pub trait EventBus: Send + Sync + Clone + 'static {
   115→    /// Publish an outbound envelope.
   116→    async fn publish(&self, evt: EventEnvelope<DomainEvent>) -> Result<(), EventBusError>;
   117→
   118→    /// Subscribe to a *broadcast* of domain events.
   119→    ///
   120→    /// Each subscriber is assigned a unique consumer group by default.
   121→    async fn subscribe(
   122→        &self,
   123→    ) -> Result<
   124→        Box<dyn Stream<Item = Result<EventEnvelope<DomainEvent>, EventBusError>> + Send + Unpin>,
   125→        EventBusError,
   126→    >;
   127→}
   128→
   129→/// Kafka-backed implementation.
   130→///
   131→/// The struct owns both a producer and a consumer (joined via a unique group id).
   132→#[derive(Clone)]
   133→pub struct KafkaEventBus {
   134→    producer: FutureProducer,
   135→    consumer: StreamConsumer,
   136→}
   137→
   138→impl KafkaEventBus {
   139→    /// Build from environment variables (see `README.md`).
   140→    ///
   141→    /// Required:
   142→    /// - `KAFKA_BROKERS`
   143→    /// - `SERVICE_NAME` (used for consumer group)
   144→    pub fn from_env() -> Result<Self, EventBusError> {
   145→        let brokers = std::env::var("KAFKA_BROKERS").unwrap_or_else(|_| "localhost:9092".into());
   146→        let service_name = std::env::var("SERVICE_NAME").unwrap_or_else(|_| "edu_pulse".into());
   147→        let group_id = format!("{service_name}-{}", Uuid::new_v4());
   148→
   149→        let common_config = || {
   150→            let mut cfg = ClientConfig::new();
   151→            cfg.set("bootstrap.servers", &brokers)
   152→                .set("enable.idempotence", "true")
   153→                .set("message.timeout.ms", "5000");
   154→            cfg
   155→        };
   156→
   157→        let producer = common_config()
   158→            .clone()
   159→            .create::<FutureProducer>()
   160→            .map_err(EventBusError::Kafka)?;
   161→
   162→        let consumer = common_config()
   163→            .set("group.id", group_id)
   164→            .set("auto.offset.reset", "earliest")
   165→            .create::<StreamConsumer>()
   166→            .map_err(EventBusError::Kafka)?;
