   178→    #[instrument(skip(self, evt), fields(event_id = %evt.id))]
   179→    async fn publish(&self, evt: EventEnvelope<DomainEvent>) -> Result<(), EventBusError> {
   180→        let payload = serde_json::to_vec(&evt)?;
