   222→/// Spawn a Tokio task that listens for events *only* to persist them to PostgreSQL for
   223→/// immutable auditing / GDPR tracing.
   224→///
   225→/// Use feature flag `postgres` to enable.
   226→///
   227→/// The table schema (PostgreSQL) expected by this routine:
   228→///
   229→/// ```sql
   230→/// CREATE TABLE IF NOT EXISTS audit_trail (
   231→///     id            UUID PRIMARY KEY,
   232→///     subject_id    UUID NOT NULL,
   233→///     created_at    TIMESTAMPTZ NOT NULL,
