   250→            match item {
   251→                Ok(envelope) => {
   252→                    let event_type = match &envelope.payload {
   253→                        DomainEvent::LessonPublished { .. } => "LessonPublished",
   254→                        DomainEvent::LearningPulseCreated { .. } => "LearningPulseCreated",
   255→                        DomainEvent::PulseSubmissionReceived { .. } => "PulseSubmissionReceived",
   256→                        DomainEvent::QuizSubmitted { .. } => "QuizSubmitted",
   257→                        DomainEvent::BadgeAwarded { .. } => "BadgeAwarded",
   258→                    };
