   260→                        r#"
   261→                        INSERT INTO audit_trail (id, subject_id, created_at, event_type, event_json)
   262→                        VALUES ($1, $2, $3, $4, $5)
   263→                        "#,
   264→                        envelope.id,
   265→                        envelope.subject_id,
   266→                        envelope.created_at,
   267→                        event_type,
   268→                        serde_json::to_value(&envelope.payload)?,
   269→                    )
   270→                    .execute(&pool)
   271→                    .await
   272→                    {
   273→                        error!(err = %e, "Failed to persist audit event");
   274→                    }
