     2→//! src/module_27.rs
     3→//! -------------------------------------------------------------
     4→//! Pulses Search–Indexing Service
     5→//! -------------------------------------------------------------
     6→//! This module implements a self-contained, production-grade worker
     7→//! that listens for `PulsePublished` domain events and (re)indexes the
     8→//! corresponding record into Elasticsearch.  The design follows
     9→//!   • Repository Pattern (database access is isolated)
    10→//!   • Service Layer      (SearchIndexer)
    11→//!   • Async / Event-driven architecture
    12→//!   • Robust error-handling + observability via `tracing`
    13→//!
    14→//! Build dependencies (add to Cargo.toml):
    15→//! ---------------------------------------
    16→//! [dependencies]
    17→//! anyhow      = "1"
    18→//! async-channel = "1"
    19→//! async-trait = "0.1"
    20→//! chrono      = { version = "0.4", features = ["serde"] }
    21→//! config      = "0.13"
    22→//! reqwest     = { version = "0.11", features = ["json", "rustls-tls"] }
    23→//! serde       = { version = "1.0", features = ["derive"] }
    24→//! serde_json  = "1.0"
    25→//! sqlx        = { version = "0.7", default-features = false, features = [ "runtime-tokio", "postgres", "macros", "chrono"] }
    26→//! thiserror   = "1"
    27→//! tokio       = { version = "1", features = ["macros", "rt-multi-thread", "signal"] }
    28→//! tracing     = "0.1"
    29→//! tracing-subscriber = { version = "0.3", features = ["env-filter", "fmt"] }
    30→//!
    31→//! -------------------------------------------------------------
    32→//! NOTE: Real broker integration (RabbitMq, NATS, etc.) is replaced by an
    33→//!       async channel to keep the snippet self-contained.
    34→//! -------------------------------------------------------------
    35→
    36→use anyhow::{Context, Result};
    37→use async_channel::{Receiver, Sender};
