    49→/// -------- Domain Events ----------------------------------------------------
    50→
    51→#[derive(Debug, Deserialize, Serialize, Clone)]
    52→#[serde(tag = "type", content = "payload")]
    53→pub enum DomainEvent {
    54→    PulsePublished { pulse_id: i64 },
