   243→/// -------- Application Bootstrap -------------------------------------------
   244→pub async fn run(settings: Settings, consumer: BrokerConsumer) -> Result<()> {
   245→    // init db
   246→    let db = PgPoolOptions::new()
   247→        .max_connections(5)
   248→        .acquire_timeout(Duration::from_secs(5))
