   250→        .await
   251→        .context("Could not connect to Postgres")?;
   252→
   253→    let repo = Arc::new(PostgresPulseRepository::new(db));
   254→    let search = Arc::new(ElasticSearchClient::new(&settings.elasticsearch_url));
