//! src/module_4.rs
//!
//! EduPulse Live – Event-Sourcing Core
//!
//! This module provides the building blocks for implementing event-sourced
//! aggregates and reliable message publishing within the "EduPulse Live"
//! platform.  Key components:
//!
//! ● `DomainEvent` – trait marking an event eligible for persistence/publishing
//! ● `EventStore` – trait for persisting events (Postgres implementation)
//! ● `EventPublisher` – trait for pushing events to the message bus (NATS impl)
//! ● `OutboxForwarder` – worker that drains the "outbox" table and publishes
//!
//! The design follows the Outbox Pattern to guarantee *exactly-once* delivery
//! even when the primary DB and the message broker are separate systems.
```

```rust
// File: /app/project/src/module_4.txt
// Lines: 240-268 (NATS JetStream Publisher)
pub struct NatsJsEventPublisher {
    nc: Arc<nats::asynk::Connection>,
    jetstream: async_nats::jetstream::Context,
}

impl NatsJsEventPublisher {
    pub async fn connect(url: &str, stream_name: &str) -> Result<Self, PublishError> {
        let nc = nats::asynk::connect(url)
            .await
            .map_err(|e| PublishError::Connection(e.to_string()))?;
        let js = async_nats::jetstream::new(nc.clone());

        // Ensure stream exists with sensible defaults
        js.get_or_create_stream(async_nats::jetstream::stream::Config {
            name: stream_name.to_string(),
            subjects: vec![format!("{stream_name}.>")],
            max_age: Duration::from_secs(60 * 60 * 24 * 7), // 7 days
            ..Default::default()
        })
        .await
        .map_err(|e| PublishError::JetStream(e.to_string()))?;

        Ok(Self {
            nc: Arc::new(nc),
            jetstream: js,
        })
    }
}
